class Money {
    private final int pounds;
    private final int pence;

    Money(int pounds, int pence) {
        this.pounds = pounds + pence / 100;
        this.pence = pence % 100;
    }
    Money add(Money other) {
        int totalPence = (this.pounds * 100 + this.pence) + (other.pounds * 100 + other.pence);
        return new Money(0, totalPence);
    }
    @Override
    public String toString() {
        return String.format("GBP%d.%02d", pounds, pence);
    }
}
public class Main {
    public static void main(String[] args) {
        Money price = new Money(9, 99);
        Money tax = new Money(2, 0);
        Money total = price.add(tax);
        System.out.println("Price: " + price);
        System.out.println("Tax: " + tax);
        System.out.println("Total: " + total);
    }
}

