class StringUtils {
    private StringUtils() {} // prevent instantiation

    static String reverse(String s) {
        return new StringBuilder(s).reverse().toString();
    }
    static boolean isPalindrome(String s) {
        String clean = s.toLowerCase().replaceAll("[^a-z]", "");
        return clean.equals(reverse(clean));
    }
    static int countVowels(String s) {
        int count = 0;
        for (char c : s.toLowerCase().toCharArray())
            if ("aeiou".indexOf(c) >= 0) count++;
        return count;
    }
}
public class Main {
    public static void main(String[] args) {
        System.out.println(StringUtils.reverse("Hello"));
        System.out.println(StringUtils.isPalindrome("Race Car"));
        System.out.println(StringUtils.countVowels("Hello World"));
    }
}

class LibBook {
    String title;
    boolean checkedOut;
    LibBook(String title) { this.title = title; this.checkedOut = false; }
    @Override public String toString() { return title + (checkedOut ? " [OUT]" : " [IN]"); }
}
class Library {
    String name;
    LibBook[] books;
    int count;
    Library(String name, int capacity) {
        this.name = name;
        this.books = new LibBook[capacity];
        this.count = 0;
    }
    void addBook(String title) {
        if (count < books.length) books[count++] = new LibBook(title);
    }
    boolean checkout(String title) {
        for (int i = 0; i < count; i++)
            if (books[i].title.equals(title) && !books[i].checkedOut) {
                books[i].checkedOut = true; return true;
            }
        return false;
    }
    void listBooks() {
        System.out.println("--- " + name + " ---");
        for (int i = 0; i < count; i++) System.out.println("  " + books[i]);
    }
}
public class Main {
    public static void main(String[] args) {
        Library lib = new Library("City Library", 10);
        lib.addBook("1984");
        lib.addBook("Dune");
        lib.addBook("Hobbit");
        lib.checkout("Dune");
        lib.listBooks();
    }
}

class StudentRecord {
    private String name;
    private int[] scores;
    private static int totalStudents = 0;

    StudentRecord(String name, int[] scores) {
        this.name = name;
        this.scores = scores.clone();
        totalStudents++;
    }
    public String getName() { return name; }
    public double getAverage() {
        int sum = 0;
        for (int s : scores) sum += s;
        return (double) sum / scores.length;
    }
    public String getGrade() {
        double avg = getAverage();
        if (avg >= 90) return "A";
        if (avg >= 80) return "B";
        if (avg >= 70) return "C";
        if (avg >= 60) return "D";
        return "F";
    }
    public static int getTotalStudents() { return totalStudents; }
    @Override
    public String toString() {
        return String.format("%s: avg=%.1f grade=%s", name, getAverage(), getGrade());
    }
}
public class Main {
    public static void main(String[] args) {
        StudentRecord s1 = new StudentRecord("Alice", new int[]{85,92,78,90});
        StudentRecord s2 = new StudentRecord("Bob", new int[]{72,68,75,80});
        System.out.println(s1);
        System.out.println(s2);
        System.out.println("Total: " + StudentRecord.getTotalStudents());
    }
}

