class RPGChar {
    private String name;private int hp,attack,defence;
    private static int charCount=0;
    RPGChar(String n,int h,int a,int d){name=n;hp=Math.max(1,h);attack=Math.max(1,a);defence=Math.max(0,d);charCount++;}
    public String getName(){return name;}
    public int getHp(){return hp;}
    public boolean isAlive(){return hp>0;}
    public void takeDamage(int d){hp-=Math.max(0,d);if(hp<0)hp=0;}
    public String attackReport(RPGChar e){int dmg=Math.max(0,attack-e.defence);return name+" attacks "+e.name+" for "+dmg+" damage ("+attack+" ATK - "+e.defence+" DEF)";}
    public static int getCount(){return charCount;}
    @Override public String toString(){return name+" [HP:"+hp+" ATK:"+attack+" DEF:"+defence+"]";}
    @Override public boolean equals(Object o){if(!(o instanceof RPGChar))return false;return name.equals(((RPGChar)o).name);}
}
